import { IncomingMessage } from 'http';
import { WebSocket } from 'ws';

export interface WebSocketContext {
    ws: WebSocket;
    req: IncomingMessage;
    url: URL;
    params: Record<string, string>;
    query: Record<string, string>;
    send: (data: any) => void;
    close: (code?: number, reason?: string) => void;
    broadcast: (data: any, exclude?: WebSocket[]) => void;
}

export interface WebSocketHandler {
    (ctx: WebSocketContext): void | Promise<void>;
}

export interface WebSocketRoute {
    path: string;
    handler: WebSocketHandler;
    pathPattern?: RegExp;
    paramNames?: string[];
}

export interface WebSocketServer {
    route: (path: string, handler: WebSocketHandler) => void;
    start: (port?: number) => void;
    broadcast: (data: any) => void;
    getConnections: () => WebSocket[];
}

import { Server } from 'http';
import { WebSocketServer as WSServer } from 'ws';
import { HightWSServer } from './server';
import { WebSocketServer, WebSocketHandler } from '../types/websocket';
import Console, { Colors } from '../api/console';

export class WebSocketAdapter {
    private wsServer: HightWSServer;
    private httpServer: Server | null = null;
    private wss: WSServer | null = null;

    constructor() {
        this.wsServer = new HightWSServer();
    }

    /**
     * Integra WebSocket com um servidor HTTP existente
     */
    attachToHttpServer(httpServer: Server): void {
        this.httpServer = httpServer;
        this.wss = new WSServer({ 
            server: httpServer,
            perMessageDeflate: false 
        });

        console.log(`${Colors.FgGreen}✓${Colors.Reset} WebSocket attached to HTTP server`);

        this.wss.on('connection', (ws, req) => {
            this.wsServer['handleConnection'](ws, req);
        });

        this.wss.on('error', (error) => {
            console.error(`${Colors.FgRed}[WebSocket Server Error]${Colors.Reset}`, error);
        });
    }

    /**
     * Adiciona uma rota WebSocket
     */
    route(path: string, handler: WebSocketHandler): void {
        this.wsServer.route(path, handler);
    }

    /**
     * Faz broadcast para todas as conexões
     */
    broadcast(data: any): void {
        this.wsServer.broadcast(data);
    }

    /**
     * Retorna todas as conexões ativas
     */
    getConnections() {
        return this.wsServer.getConnections();
    }

    /**
     * Inicia servidor WebSocket standalone
     */
    startStandalone(port: number = 8080): void {
        this.wsServer.start(port);
    }
}

import React from 'react';

export class HightWSClient {
    private ws: WebSocket | null = null;
    private url: string;
    private reconnectAttempts: number = 0;
    private maxReconnectAttempts: number = 5;
    private reconnectDelay: number = 1000;
    private listeners: Map<string, Function[]> = new Map();

    constructor(url: string) {
        this.url = url;
        this.connect();
    }

    private connect(): void {
        try {
            this.ws = new WebSocket(this.url);

            this.ws.onopen = (event) => {
                console.log('[HightWS] Connected to WebSocket server');
                this.reconnectAttempts = 0;
                this.emit('open', event);
            };

            this.ws.onmessage = (event) => {
                try {
                    const data = JSON.parse(event.data);
                    this.emit('message', data);
                } catch (error) {
                    // Se não for JSON, envia como string
                    this.emit('message', event.data);
                }
            };

            this.ws.onclose = (event) => {
                console.log('[HightWS] Connection closed');
                this.emit('close', event);
                this.attemptReconnect();
            };

            this.ws.onerror = (event) => {
                console.error('[HightWS] WebSocket error:', event);
                this.emit('error', event);
            };

        } catch (error) {
            console.error('[HightWS] Failed to connect:', error);
            this.attemptReconnect();
        }
    }

    private attemptReconnect(): void {
        if (this.reconnectAttempts < this.maxReconnectAttempts) {
            this.reconnectAttempts++;
            console.log(`[HightWS] Attempting to reconnect (${this.reconnectAttempts}/${this.maxReconnectAttempts})...`);

            setTimeout(() => {
                this.connect();
            }, this.reconnectDelay * this.reconnectAttempts);
        } else {
            console.error('[HightWS] Max reconnection attempts reached');
            this.emit('maxReconnectAttemptsReached');
        }
    }

    public send(data: any): void {
        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
            const message = typeof data === 'string' ? data : JSON.stringify(data);
            this.ws.send(message);
        } else {
            console.warn('[HightWS] WebSocket is not connected');
        }
    }

    public on(event: string, callback: Function): void {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, []);
        }
        this.listeners.get(event)!.push(callback);
    }

    public off(event: string, callback?: Function): void {
        if (!this.listeners.has(event)) return;

        if (callback) {
            const callbacks = this.listeners.get(event)!;
            const index = callbacks.indexOf(callback);
            if (index > -1) {
                callbacks.splice(index, 1);
            }
        } else {
            this.listeners.delete(event);
        }
    }

    private emit(event: string, data?: any): void {
        if (this.listeners.has(event)) {
            this.listeners.get(event)!.forEach(callback => {
                try {
                    callback(data);
                } catch (error) {
                    console.error(`[HightWS] Error in event listener for ${event}:`, error);
                }
            });
        }
    }

    public close(): void {
        if (this.ws) {
            this.ws.close();
            this.ws = null;
        }
    }

    public get readyState(): number {
        return this.ws ? this.ws.readyState : WebSocket.CLOSED;
    }

    public get isConnected(): boolean {
        return this.ws !== null && this.ws.readyState === WebSocket.OPEN;
    }
}

// Hook React para usar WebSocket
export function useWebSocket(url: string) {
    const [client, setClient] = React.useState<HightWSClient | null>(null);
    const [isConnected, setIsConnected] = React.useState(false);
    const [lastMessage, setLastMessage] = React.useState<any>(null);

    React.useEffect(() => {
        const wsClient = new HightWSClient(url);

        wsClient.on('open', () => {
            setIsConnected(true);
        });

        wsClient.on('close', () => {
            setIsConnected(false);
        });

        wsClient.on('message', (data) => {
            setLastMessage(data);
        });

        setClient(wsClient);

        return () => {
            wsClient.close();
        };
    }, [url]);

    const sendMessage = React.useCallback((data: any) => {
        if (client) {
            client.send(data);
        }
    }, [client]);

    return {
        client,
        isConnected,
        lastMessage,
        sendMessage
    };
}

// Exemplo de uso do WebSocket no HightJS

// ============================================
// BACKEND - Como criar rotas WebSocket
// ============================================

// Em src/web/backend/websocket.ts (ou qualquer arquivo backend)
import { ws } from 'hightjs/ws';

// Rota simples de chat
ws('/chat', (ctx) => {
    console.log('Nova conexão no chat:', ctx.req.socket.remoteAddress);

    // Envia mensagem de boas-vindas
    ctx.send({
        type: 'welcome',
        message: 'Bem-vindo ao chat!'
    });

    // Escuta mensagens do cliente
    ctx.ws.on('message', (data) => {
        try {
            const message = JSON.parse(data.toString());

            // Faz broadcast da mensagem para todos os outros clientes
            ctx.broadcast({
                type: 'message',
                user: message.user || 'Anônimo',
                text: message.text,
                timestamp: new Date().toISOString()
            }, [ctx.ws]); // Exclui o remetente

        } catch (error) {
            console.error('Erro ao processar mensagem:', error);
        }
    });

    // Quando a conexão fechar
    ctx.ws.on('close', () => {
        console.log('Cliente desconectado do chat');
    });
});

// Rota com parâmetros
ws('/room/:roomId', (ctx) => {
    const { roomId } = ctx.params;
    console.log(`Nova conexão na sala: ${roomId}`);

    ctx.send({
        type: 'joined',
        room: roomId,
        message: `Você entrou na sala ${roomId}`
    });
});

// Rota para notificações em tempo real
ws('/notifications/:userId', (ctx) => {
    const { userId } = ctx.params;

    // Pode usar query params também
    const token = ctx.query.token;

    if (!token) {
        ctx.close(1008, 'Token obrigatório');
        return;
    }

    console.log(`Usuário ${userId} conectado para notificações`);

    // Simula envio de notificação a cada 30 segundos
    const interval = setInterval(() => {
        ctx.send({
            type: 'notification',
            title: 'Nova notificação',
            body: 'Você tem uma nova mensagem',
            timestamp: new Date().toISOString()
        });
    }, 30000);

    ctx.ws.on('close', () => {
        clearInterval(interval);
        console.log(`Usuário ${userId} desconectado das notificações`);
    });
});

// ============================================
// FRONTEND - Como usar WebSocket no React
// ============================================

// Em qualquer componente React
import React from 'react';
import { HightWSClient, useWebSocket } from 'hightjs/ws';

// Método 1: Usando o hook useWebSocket (mais fácil)
function ChatComponent() {
    const { client, isConnected, lastMessage, sendMessage } = useWebSocket('ws://localhost:8080/chat');
    const [messages, setMessages] = React.useState([]);
    const [newMessage, setNewMessage] = React.useState('');

    // Atualiza mensagens quando recebe uma nova
    React.useEffect(() => {
        if (lastMessage && lastMessage.type === 'message') {
            setMessages(prev => [...prev, lastMessage]);
        }
    }, [lastMessage]);

    const handleSendMessage = () => {
        if (newMessage.trim() && isConnected) {
            sendMessage({
                user: 'Seu Nome',
                text: newMessage
            });
            setNewMessage('');
        }
    };

    return (
        <div>
            <div>Status: {isConnected ? 'Conectado' : 'Desconectado'}</div>

            <div style={{ height: '300px', overflow: 'auto', border: '1px solid #ccc' }}>
                {messages.map((msg, index) => (
                    <div key={index}>
                        <strong>{msg.user}:</strong> {msg.text}
                        <small> ({new Date(msg.timestamp).toLocaleTimeString()})</small>
                    </div>
                ))}
            </div>

            <div>
                <input
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                    placeholder="Digite sua mensagem..."
                />
                <button onClick={handleSendMessage} disabled={!isConnected}>
                    Enviar
                </button>
            </div>
        </div>
    );
}

// Método 2: Usando a classe HightWSClient diretamente (mais controle)
function NotificationsComponent() {
    const [client, setClient] = React.useState(null);
    const [notifications, setNotifications] = React.useState([]);
    const userId = '123'; // ID do usuário atual

    React.useEffect(() => {
        const wsClient = new HightWSClient(`ws://localhost:8080/notifications/${userId}?token=abc123`);

        wsClient.on('open', () => {
            console.log('Conectado às notificações');
        });

        wsClient.on('message', (data) => {
            if (data.type === 'notification') {
                setNotifications(prev => [data, ...prev.slice(0, 9)]); // Mantém só as 10 últimas

                // Pode mostrar notificação do browser também
                if (Notification.permission === 'granted') {
                    new Notification(data.title, { body: data.body });
                }
            }
        });

        wsClient.on('close', () => {
            console.log('Desconectado das notificações');
        });

        setClient(wsClient);

        return () => {
            wsClient.close();
        };
    }, [userId]);

    return (
        <div>
            <h3>Notificações em tempo real</h3>
            {notifications.map((notif, index) => (
                <div key={index} style={{ padding: '10px', border: '1px solid #ddd', margin: '5px 0' }}>
                    <strong>{notif.title}</strong>
                    <p>{notif.body}</p>
                    <small>{new Date(notif.timestamp).toLocaleString()}</small>
                </div>
            ))}
        </div>
    );
}

