// No seu arquivo principal de servidor (onde você inicia o HightJS)
import { createWebSocketServer } from 'hightjs/ws';

// Método 1: Servidor WebSocket independente
const wsServer = createWebSocketServer();
wsServer.start(8080); // Inicia na porta 8080

// Método 2: Integrar com servidor HTTP existente (Express/Fastify)
// Isso ainda precisa ser implementado nos adapters, mas a estrutura está pronta

export default ChatComponent;

import { HightWSServer } from './server';
import { WebSocketServer } from '../types/websocket';

/**
 * Cria uma nova instância do servidor WebSocket HightJS
 * @returns Uma nova instância do servidor WebSocket
 */
export function createWebSocketServer(): WebSocketServer {
    return new HightWSServer();
}

/**
 * Instância global do servidor WebSocket (singleton)
 */
let globalWSServer: WebSocketServer | null = null;

/**
 * Retorna a instância global do servidor WebSocket ou cria uma nova
 * @returns A instância global do servidor WebSocket
 */
export function getGlobalWebSocketServer(): WebSocketServer {
    if (!globalWSServer) {
        globalWSServer = new HightWSServer();
    }
    return globalWSServer;
}

/**
 * Helper para criar rotas WebSocket rapidamente
 * @param path Caminho da rota
 * @param handler Função handler da rota
 */
export function ws(path: string, handler: (ctx: any) => void | Promise<void>) {
    const server = getGlobalWebSocketServer();
    server.route(path, handler);
    return server;
}

export { HightWSServer } from './server';
export { WebSocketContext, WebSocketHandler, WebSocketRoute, WebSocketServer } from '../types/websocket';
export { createWebSocketServer } from './factory';
export { HightWSClient, useWebSocket } from './client';

import { WebSocket, WebSocketServer as WSServer } from 'ws';
import { IncomingMessage } from 'http';
import { URL } from 'url';
import { WebSocketContext, WebSocketHandler, WebSocketRoute, WebSocketServer } from '../types/websocket';
import Console, { Colors } from '../api/console';

export class HightWSServer implements WebSocketServer {
    private wss: WSServer | null = null;
    private routes: WebSocketRoute[] = [];
    private connections: Set<WebSocket> = new Set();

    constructor() {
        this.setupRoutePatterns();
    }

    route(path: string, handler: WebSocketHandler): void {
        const route: WebSocketRoute = {
            path,
            handler,
            ...this.createPathPattern(path)
        };
        this.routes.push(route);
        console.log(`${Colors.FgBlue}[WebSocket]${Colors.Reset} Route registered: ${Colors.FgYellow}${path}${Colors.Reset}`);
    }

    start(port: number = 8080): void {
        this.wss = new WSServer({ 
            port,
            perMessageDeflate: false 
        });

        console.log(`${Colors.FgGreen}✓${Colors.Reset} WebSocket server listening on port ${Colors.FgYellow}${port}${Colors.Reset}`);

        this.wss.on('connection', (ws: WebSocket, req: IncomingMessage) => {
            this.connections.add(ws);
            console.log(`${Colors.FgBlue}[WebSocket]${Colors.Reset} New connection from ${req.socket.remoteAddress}`);

            ws.on('close', () => {
                this.connections.delete(ws);
                console.log(`${Colors.FgBlue}[WebSocket]${Colors.Reset} Connection closed`);
            });

            ws.on('error', (error) => {
                console.error(`${Colors.FgRed}[WebSocket Error]${Colors.Reset}`, error);
                this.connections.delete(ws);
            });

            this.handleConnection(ws, req);
        });

        this.wss.on('error', (error) => {
            console.error(`${Colors.FgRed}[WebSocket Server Error]${Colors.Reset}`, error);
        });
    }

    broadcast(data: any): void {
        const message = typeof data === 'string' ? data : JSON.stringify(data);
        this.connections.forEach(ws => {
            if (ws.readyState === WebSocket.OPEN) {
                ws.send(message);
            }
        });
    }

    getConnections(): WebSocket[] {
        return Array.from(this.connections);
    }

    private handleConnection(ws: WebSocket, req: IncomingMessage): void {
        if (!req.url) return;

        const url = new URL(req.url, `http://${req.headers.host}`);
        const pathname = url.pathname;

        // Encontra a rota correspondente
        const matchedRoute = this.findMatchingRoute(pathname);
        if (!matchedRoute) {
            console.log(`${Colors.FgYellow}[WebSocket]${Colors.Reset} No route found for ${pathname}`);
            ws.close(1000, 'No route found');
            return;
        }

        // Extrai parâmetros da URL
        const params = this.extractParams(pathname, matchedRoute);
        const query = Object.fromEntries(url.searchParams.entries());

        // Cria o contexto
        const context: WebSocketContext = {
            ws,
            req,
            url,
            params,
            query,
            send: (data: any) => {
                if (ws.readyState === WebSocket.OPEN) {
                    const message = typeof data === 'string' ? data : JSON.stringify(data);
                    ws.send(message);
                }
            },
            close: (code?: number, reason?: string) => {
                ws.close(code || 1000, reason);
            },
            broadcast: (data: any, exclude?: WebSocket[]) => {
                const message = typeof data === 'string' ? data : JSON.stringify(data);
                const excludeSet = new Set(exclude || []);
                this.connections.forEach(connection => {
                    if (connection.readyState === WebSocket.OPEN && !excludeSet.has(connection)) {
                        connection.send(message);
                    }
                });
            }
        };

        try {
            matchedRoute.handler(context);
        } catch (error) {
            console.error(`${Colors.FgRed}[WebSocket Handler Error]${Colors.Reset}`, error);
            ws.close(1011, 'Internal server error');
        }
    }

    private createPathPattern(path: string): { pathPattern: RegExp; paramNames: string[] } {
        const paramNames: string[] = [];
        const pattern = path
            .replace(/\//g, '\\/')
            .replace(/:([^\/]+)/g, (_, paramName) => {
                paramNames.push(paramName);
                return '([^/]+)';
            })
            .replace(/\*/g, '.*');

        return {
            pathPattern: new RegExp(`^${pattern}$`),
            paramNames
        };
    }

    private findMatchingRoute(pathname: string): WebSocketRoute | null {
        return this.routes.find(route => {
            if (route.pathPattern) {
                return route.pathPattern.test(pathname);
            }
            return route.path === pathname;
        }) || null;
    }

    private extractParams(pathname: string, route: WebSocketRoute): Record<string, string> {
        const params: Record<string, string> = {};

        if (route.pathPattern && route.paramNames) {
            const match = pathname.match(route.pathPattern);
            if (match) {
                route.paramNames.forEach((paramName, index) => {
                    params[paramName] = match[index + 1];
                });
            }
        }

        return params;
    }

    private setupRoutePatterns(): void {
        // Reprocessa todos os patterns das rotas existentes
        this.routes.forEach(route => {
            const { pathPattern, paramNames } = this.createPathPattern(route.path);
            route.pathPattern = pathPattern;
            route.paramNames = paramNames;
        });
    }
}
